109	                    label = { Text(stringResource(R.string.history)) },
110	                    selected = selectedTab == 1,
111	                    onClick = { selectedTab = 1 }
112	                )
113	                NavigationBarItem(
114	                    icon = { Icon(Icons.Outlined.Notifications, contentDescription = null) },
115	                    label = { Text("计时") },
116	                    selected = selectedTab == 2,
117	                    onClick = { selectedTab = 2 }
118	                )
119	            }
120	        }
121	    ) { padding ->
122	        // 使用Box而不是Column，以避免fillMaxSize导致的布局问题
123	        Box(
124	            modifier = Modifier
125	                .fillMaxSize()
126	                .padding(padding)
127	        ) {
128	            when (selectedTab) {
129	                0 -> RealTimeHeartRateScreen(
130	                    viewModel, 
131	                    connectAttemptId, 
132	                    { connectAttemptId = it },
133	                    hasAutoConnectAttempted,
134	                    { hasAutoConnectAttempted = it },
135	                    hasAutoConnectedDevice,
136	                    { hasAutoConnectedDevice = it }
137	                )
138	                1 -> HeartRateHistoryScreen(viewModel)
139	                2 -> TimerHistoryScreen(viewModel)
140	            }
141	        }
142	    }
143	}
144	
145	/**
146	 * 实时心率屏幕
147	 */
148	@OptIn(ExperimentalMaterial3Api::class, ExperimentalPermissionsApi::class)
149	@Composable
150	fun RealTimeHeartRateScreen(
151	    viewModel: HeartRateViewModel = viewModel(), 
152	    connectAttemptId: Int, 
153	    onConnectAttemptIdChange: (Int) -> Unit = {},
154	    hasAutoConnectAttempted: Boolean,
155	    onHasAutoConnectAttemptedChange: (Boolean) -> Unit,
156	    hasAutoConnectedDevice: Boolean,
157	    onHasAutoConnectedDeviceChange: (Boolean) -> Unit
158	) {
159	    val context = LocalContext.current
160	    val currentHeartRate by viewModel.currentHeartRate.collectAsState()
161	    val connectionState by viewModel.connectionState.collectAsState()
162	    val highThreshold by viewModel.highThreshold.collectAsState()
163	    val lowThreshold by viewModel.lowThreshold.collectAsState()
164	    val autoReconnectState by viewModel.autoReconnectState.collectAsState()
165	    val lastDeviceAddress by viewModel.lastDeviceAddress.collectAsState()
166	
167	    // 权限状态
168	    val permissionsState = rememberMultiplePermissionsState(
169	        permissions = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
170	            listOf(
171	                Manifest.permission.BLUETOOTH_SCAN,
172	                Manifest.permission.BLUETOOTH_CONNECT
173	            )
174	        } else {
175	            listOf(Manifest.permission.ACCESS_FINE_LOCATION)
176	        }
177	    )
178	
179	    // Track previous state to avoid showing toast when switching tabs
180	    var previousState by remember { mutableStateOf(connectionState) }
181	
182	    LaunchedEffect(connectionState) {
183	        if (connectionState is ConnectionState.CONNECTED && previousState !is ConnectionState.CONNECTED) {
184	            Toast.makeText(context, "已连接高驰心率带", Toast.LENGTH_SHORT).show()
185	        }
186	        previousState = connectionState
187	    }
188	    
189	    // 自动重连提示
190	    LaunchedEffect(autoReconnectState) {
191	        when (autoReconnectState) {
192	            is AutoReconnectState.RECONNECTING -> {
193	                val state = autoReconnectState as AutoReconnectState.RECONNECTING
194	                Toast.makeText(context, "正在尝试自动重连 (${state.attempt}/${state.maxAttempts})...", Toast.LENGTH_SHORT).show()
195	            }
196	            is AutoReconnectState.FAILED -> {
197	                Toast.makeText(context, "自动重连失败，请手动连接", Toast.LENGTH_LONG).show()
198	            }
199	            else -> {}
200	        }
201	    }
202	    
203	    // 自动扫描并连接心率带（只执行一次）
204	    // 优先检查是否已连接，如果已连接则直接显示数据
205	    LaunchedEffect(permissionsState.allPermissionsGranted) {
206	        if (!permissionsState.allPermissionsGranted) return@LaunchedEffect
207	        if (hasAutoConnectAttempted) return@LaunchedEffect
208	
209	        onHasAutoConnectAttemptedChange(true)
210	
211	        // 首先检查是否已经连接了心率带
212	        if (connectionState is ConnectionState.CONNECTED) {
213	            // 已连接，直接显示数据，不需要任何操作
214	            Toast.makeText(context, "已连接高驰心率带", Toast.LENGTH_SHORT).show()
215	            onHasAutoConnectedDeviceChange(true)
216	            return@LaunchedEffect
217	        }
218	
219	        // 未连接，等待一小段时间确保 lastDeviceAddress 从 DataStore 加载完成
220	        kotlinx.coroutines.delay(500)
221	
222	        // 如果有保存的设备地址，直接尝试连接
223	        val savedAddress = lastDeviceAddress
224	        if (!savedAddress.isNullOrEmpty()) {
225	            Toast.makeText(context, "正在自动连接心率带...", Toast.LENGTH_SHORT).show()
226	            viewModel.connectToDevice(savedAddress)
227	        } else {
228	            // 没有保存的设备地址，开始扫描
229	            viewModel.startScan()
230	        }
231	    }
232	    
233	    // 自动连接扫描到的第一个设备
234	    val scannedDevices by viewModel.scannedDevices.collectAsState()
235	    val scanState by viewModel.scanState.collectAsState()
236	    val savedDeviceAddress = lastDeviceAddress // 缓存避免重复获取
237	    
238	    // 显示扫描状态
239	    LaunchedEffect(scanState) {
240	        when (scanState) {
241	            is BleScanner.ScanState.SCANNING -> {
242	                if (!hasAutoConnectedDevice && savedDeviceAddress.isNullOrEmpty()) {
243	                    Toast.makeText(context, "正在扫描心率带...", Toast.LENGTH_SHORT).show()
244	                }
245	            }
